// =============================================================================
// Memory Management & Error Retrieval
// =============================================================================

/// Free memory allocated by native API functions.
/// The allocation size is recovered from the prepended header.
#[no_mangle]
pub unsafe extern "C" fn volvox_grid_free(ptr: *mut u8) {
    free_payload_with_header(ptr);
}

/// Returns a pointer to the last error message (UTF-8, not null-terminated).
/// The pointer is valid until the next FFI call into this module.
/// Returns null if no error has occurred. Writes the byte length to `out_len`.
#[no_mangle]
pub unsafe extern "C" fn volvox_grid_last_error(out_len: *mut i32) -> *const u8 {
    LAST_ERROR.with(|e| {
        let msg = e.borrow();
        if msg.is_empty() {
            if !out_len.is_null() {
                *out_len = 0;
            }
            return std::ptr::null();
        }
        if !out_len.is_null() {
            *out_len = msg.len() as i32;
        }
        msg.as_ptr()
    })
}

